import React, { useState, useEffect, useRef } from 'react';
import { io } from 'socket.io-client';

const StreamAnalyzer = () => {
    // Socket
    const socketRef = useRef(null);
    const [status, setStatus] = useState('Disconnected');

    // Media Refs
    const videoRef = useRef(null);
    const canvasRef = useRef(null);
    const audioContextRef = useRef(null);
    const scriptProcessorRef = useRef(null);
    const audioStreamRef = useRef(null);

    // State
    const [isVideoActive, setIsVideoActive] = useState(false);
    const [isAudioActive, setIsAudioActive] = useState(false);
    const [sensitivity, setSensitivity] = useState(0.5); // 0.5 = Normal, 0.2 = General

    // Results

    // Results
    const [stressResult, setStressResult] = useState(null);
    const [lastUpdate, setLastUpdate] = useState(null);

    // Config
    const VIDEO_FPS = 5;
    const AUDIO_BUFFER_SIZE = 4096;

    useEffect(() => {
        // Connect to Socket.IO
        socketRef.current = io('http://localhost:5000');

        socketRef.current.on('connect', () => {
            setStatus('Connected');
        });

        socketRef.current.on('disconnect', () => {
            setStatus('Disconnected');
        });

        socketRef.current.on('status', (data) => {
            console.log('Server Status:', data.msg);
        });

        socketRef.current.on('stress_update', (data) => {
            setLastUpdate(new Date());
            setStressResult(prev => ({
                ...prev,
                [data.type]: data.result
            }));
        });

        return () => {
            stopVideo();
            stopAudio();
            if (socketRef.current) socketRef.current.disconnect();
        };
    }, []);

    // ---------------------------
    // Video Handling
    // ---------------------------
    const startVideo = async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ video: { width: 320, height: 240 } });
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
                setIsVideoActive(true);

                // Start sending frames
                const interval = setInterval(() => {
                    sendVideoFrame();
                }, 1000 / VIDEO_FPS);

                videoRef.current.frameInterval = interval;
            }
        } catch (err) {
            console.error("Error accessing webcam:", err);
            alert("Could not access webcam");
        }
    };

    const stopVideo = () => {
        if (videoRef.current && videoRef.current.srcObject) {
            const tracks = videoRef.current.srcObject.getTracks();
            tracks.forEach(track => track.stop());
            videoRef.current.srcObject = null;
            clearInterval(videoRef.current.frameInterval);
        }
        setIsVideoActive(false);
    };

    const sendVideoFrame = () => {
        if (videoRef.current && canvasRef.current && socketRef.current) {
            const context = canvasRef.current.getContext('2d');
            canvasRef.current.width = videoRef.current.videoWidth;
            canvasRef.current.height = videoRef.current.videoHeight;
            context.drawImage(videoRef.current, 0, 0);

            const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.7); // 0.7 quality
            socketRef.current.emit('stream_video', {
                image: dataUrl,
                sensitivity: sensitivity
            });
        }
    };

    // ---------------------------
    // Audio Handling
    // ---------------------------
    // ---------------------------
    // Audio Handling (MediaRecorder)
    // ---------------------------
    const startAudio = async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            audioStreamRef.current = stream;
            setIsAudioActive(true);

            // Use MediaRecorder for better performance and format handling
            // Request standard mime type
            const mimeType = MediaRecorder.isTypeSupported('audio/webm;codecs=opus')
                ? 'audio/webm;codecs=opus'
                : 'audio/webm';

            const mediaRecorder = new MediaRecorder(stream, { mimeType });
            scriptProcessorRef.current = mediaRecorder; // Reuse ref for cleanup

            mediaRecorder.ondataavailable = async (event) => {
                if (event.data.size > 0 && socketRef.current) {
                    // Send raw blob buffer to backend for robust decoding
                    // This avoids the "Unable to decode audio data" error in browser
                    socketRef.current.emit('stream_audio', {
                        audio: event.data, // Socket.io handles Blobs/Buffers
                        sr: 44100, // Default assumption, backend will resample
                        sensitivity: sensitivity
                    });
                }
            };

            // Capture 1-second chunks
            mediaRecorder.start(1000);

        } catch (err) {
            console.error("Error accessing microphone:", err);
            alert("Could not access microphone");
        }
    };

    const stopAudio = () => {
        if (scriptProcessorRef.current && scriptProcessorRef.current.state !== 'inactive') {
            scriptProcessorRef.current.stop();
        }
        if (audioStreamRef.current) {
            audioStreamRef.current.getTracks().forEach(track => track.stop());
        }
        setIsAudioActive(false);
    };

    // ---------------------------
    // Render
    // ---------------------------

    // Helper to get stress details from result object
    const getResultDisplay = (type) => {
        if (!stressResult || !stressResult[type]) return "Waiting for data...";

        const data = stressResult[type];
        if (data.error) return `Error: ${data.error}`;

        // Handle audio 'buffering' status
        if (data.status === 'buffering') return "Buffering audio...";

        return `${data.predicted_class} (${data.percentage.toFixed(1)}%) - ${data.stress_level}`;
    };

    const getStressColor = (type) => {
        if (!stressResult || !stressResult[type] || stressResult[type].error || stressResult[type].status === 'buffering') return '#666';
        return stressResult[type].predicted_class === 'Stress' ? '#f44336' : '#4caf50';
    };

    return (
        <div className="neon-card mt-4">
            <h3 className="text-center mb-4">🔴 Live Real-Time Analysis</h3>

            <div className="text-center mb-3">
                <span className={`badge ${status === 'Connected' ? 'bg-success' : 'bg-danger'} me-2`}>
                    Server: {status}
                </span>

                {/* Mode Toggle */}
                <div className="btn-group" role="group">
                    <button
                        type="button"
                        className={`btn btn-sm ${sensitivity < 0.3 ? 'btn-success' : 'btn-outline-secondary'}`}
                        onClick={() => setSensitivity(0.1)}
                    >
                        🌍 General Mode
                    </button>
                    <button
                        type="button"
                        className={`btn btn-sm ${sensitivity >= 0.3 ? 'btn-danger' : 'btn-outline-secondary'}`}
                        onClick={() => setSensitivity(0.5)}
                    >
                        🩺 Clinical Mode
                    </button>
                </div>
            </div>

            <div className="row">
                {/* Video Column */}
                <div className="col-md-6 mb-4">
                    <div style={{
                        border: '2px solid rgba(178, 187, 95, 0.3)',
                        borderRadius: '12px',
                        padding: '1rem',
                        background: '#000'
                    }}>
                        <h5 className="text-white mb-3">🎥 Video Stream</h5>
                        <div style={{ position: 'relative', minHeight: '240px', background: '#222', borderRadius: '8px', overflow: 'hidden' }}>
                            <video
                                ref={videoRef}
                                autoPlay
                                playsInline
                                muted
                                style={{ width: '100%', height: '100%', objectFit: 'cover', display: isVideoActive ? 'block' : 'none' }}
                            />
                            {!isVideoActive && (
                                <div style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', color: '#666' }}>
                                    Camera Off
                                </div>
                            )}
                            {/* Hidden canvas for grabbing frames */}
                            <canvas ref={canvasRef} style={{ display: 'none' }} />
                        </div>

                        <div className="mt-3 d-grid gap-2">
                            {!isVideoActive ? (
                                <button className="btn btn-neon" onClick={startVideo}>Start Camera</button>
                            ) : (
                                <button className="btn btn-outline-danger" onClick={stopVideo}>Stop Camera</button>
                            )}
                        </div>

                        <div className="mt-3 text-center">
                            <h5 style={{ color: getStressColor('video') }}>
                                {getResultDisplay('video')}
                            </h5>
                        </div>
                    </div>
                </div>

                {/* Audio Column */}
                <div className="col-md-6 mb-4">
                    <div style={{
                        border: '2px solid rgba(178, 187, 95, 0.3)',
                        borderRadius: '12px',
                        padding: '1rem',
                        background: '#1a1a1a'
                    }}>
                        <h5 className="text-white mb-3">🎙️ Audio Stream</h5>

                        <div style={{
                            height: '100px',
                            background: isAudioActive ? 'rgba(76, 175, 80, 0.1)' : '#222',
                            borderRadius: '8px',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            marginBottom: '1rem',
                            border: isAudioActive ? '2px solid #4caf50' : 'none'
                        }}>
                            {isAudioActive ? (
                                <div className="text-success blink">● Live Audio Active</div>
                            ) : (
                                <div className="text-muted">Microphone Off</div>
                            )}
                        </div>

                        <div className="d-grid gap-2">
                            {!isAudioActive ? (
                                <button className="btn btn-neon" onClick={startAudio}>Start Microphone</button>
                            ) : (
                                <button className="btn btn-outline-danger" onClick={stopAudio}>Stop Microphone</button>
                            )}
                        </div>

                        <div className="mt-3 text-center">
                            <h5 style={{ color: getStressColor('audio') }}>
                                {getResultDisplay('audio')}
                            </h5>
                        </div>
                    </div>
                </div>
            </div>

            <div className="text-center text-muted mt-2" style={{ fontSize: '0.8rem' }}>
                Live updates every ~1s for audio and ~200ms for video. Requires backend running.
            </div>
        </div>
    );
};

export default StreamAnalyzer;
